mapper.select:
SELECT COUNT(*)
FROM user_behavior
WHERE user_id = #{userId}
  AND topic_id = #{topicId}
  AND is_valid = 1
  AND created_at >= #{startTime}

SELECT COUNT(DISTINCT user_id)
FROM user_behavior
WHERE device_fingerprint = #{deviceFingerprint}
  AND created_at >= #{startTime}

mapper.update:
UPDATE user_behavior
SET is_valid = 0, invalid_reason = #{reason}
WHERE id = #{id}
